import React, { useState } from "react";
import StatusBadge from "./StatusBadge";
import AttachmentUploadModal from "./AttachmentUploadModal";

const STATUSES = ["New", "In Transit", "Delivered", "Cancelled"];
const BILLING_STATUSES = ["Pending", "Invoiced", "Paid", "Factored"];
const DISPATCHERS = ["Asilbek Karimov", "Bobur Toshmatov"];
const US_STATES = ["AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY"];
const BROKERS = ["XPO Logistics", "Echo Global", "Coyote Logistics", "CH Robinson", "Transplace"];
const DRIVERS_LIST = ["Xumotyun Baxriddinov", "Bobur Toshmatov", "Sardor Yusupov", "Jasur Mirzayev"];
const TRUCKS = ["TRK-001", "TRK-002", "TRK-003", "TRK-007"];
const TRAILERS = ["TRL-012", "TRL-023", "TRL-044", "TRL-055"];

const initialLoads = [
  { id: "LD-20241", date: "04/30/26", driver: "Xumotyun Baxriddinov", broker: "XPO Logistics", po: "PO-8821", pickup: "New York Mills, MN", delivery: "Brookland, AR", rate: "$2,480.00", completed: "05/02/26", status: "In Transit", billing: "Pending", notes: "", attachments: 1 },
  { id: "LD-20235", date: "04/28/26", driver: "Bobur Toshmatov", broker: "Echo Global", po: "PO-8801", pickup: "Chicago, IL", delivery: "Dallas, TX", rate: "$1,840.00", completed: "05/03/26", status: "Delivered", billing: "Invoiced", notes: "", attachments: 2 },
  { id: "LD-20228", date: "04/27/26", driver: "Sardor Yusupov", broker: "CH Robinson", po: "PO-8795", pickup: "Atlanta, GA", delivery: "Memphis, TN", rate: "$786.00", completed: "05/01/26", status: "Delivered", billing: "Paid", notes: "Lumper required", attachments: 0 },
];

const emptyForm = () => ({
  status: "New", billingStatus: "Pending", dispatcher: "Asilbek Karimov",
  pickupDate: "", pickupCity: "", pickupState: "", pickupZip: "",
  deliveryDate: "", deliveryCity: "", deliveryState: "", deliveryZip: "",
  broker: "", po: "", rate: "",
  driver: "", truck: "", trailer: "",
  notes: "", attachments: [],
});

const iStyle = {
  width: "100%", border: "1px solid #d1d5db", borderRadius: 3,
  padding: "5px 8px", fontSize: 12, color: "#374151",
  outline: "none", background: "#fff", height: 30,
};
const sStyle = { ...iStyle, cursor: "pointer" };

function SectionTitle({ icon, text }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 5, marginBottom: 8 }}>
      <span style={{ color: "#3a8c5c", fontSize: 13 }}>{icon}</span>
      <span style={{ fontSize: 12, fontWeight: 600, color: "#111827" }}>{text}</span>
    </div>
  );
}

function FL({ label, children }) {
  return (
    <div style={{ marginBottom: 8 }}>
      {label && <label style={{ display: "block", fontSize: 11, color: "#6b7280", marginBottom: 3, fontWeight: 500 }}>{label}</label>}
      {children}
    </div>
  );
}

export default function LoadsPage() {
  const [loads, setLoads] = useState(initialLoads);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState(emptyForm());
  const [attachModal, setAttachModal] = useState(false);
  const [search, setSearch] = useState("");

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const handleCreate = () => {
    const newLoad = {
      id: `LD-${20000 + Math.floor(Math.random() * 999)}`,
      date: new Date().toLocaleDateString("en-US", { month: "2-digit", day: "2-digit", year: "2-digit" }),
      driver: form.driver,
      broker: form.broker,
      po: form.po || "—",
      pickup: `${form.pickupCity}${form.pickupState ? ", " + form.pickupState : ""}`,
      delivery: `${form.deliveryCity}${form.deliveryState ? ", " + form.deliveryState : ""}`,
      rate: form.rate ? `$${parseFloat(form.rate).toLocaleString("en-US", { minimumFractionDigits: 2 })}` : "$0.00",
      completed: form.deliveryDate || "—",
      status: form.status,
      billing: form.billingStatus,
      notes: form.notes,
      attachments: form.attachments.length,
    };
    setLoads(p => [newLoad, ...p]);
    setForm(emptyForm());
    setShowForm(false);
  };

  const handleAttachSave = (att) => {
    setForm(p => ({ ...p, attachments: [...p.attachments, att] }));
  };

  const filtered = loads.filter(l =>
    search === "" ||
    l.id.toLowerCase().includes(search.toLowerCase()) ||
    l.driver.toLowerCase().includes(search.toLowerCase()) ||
    l.broker.toLowerCase().includes(search.toLowerCase())
  );

  const totalRate = loads.reduce((sum, l) => {
    const n = parseFloat((l.rate || "0").replace(/[$,]/g, ""));
    return sum + (isNaN(n) ? 0 : n);
  }, 0);

  return (
    <div style={{ padding: "16px 20px" }}>
      {attachModal && <AttachmentUploadModal onClose={() => setAttachModal(false)} onSave={handleAttachSave} />}

      {/* Page Header */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14, flexWrap: "wrap", gap: 8 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <h1 style={{ fontSize: 16, fontWeight: 600, color: "#111827", margin: 0 }}>Loads</h1>
          <select style={{ border: "1px solid #d1d5db", borderRadius: 3, padding: "3px 8px", fontSize: 11, background: "#fff", color: "#374151" }}>
            <option>All</option><option>Active</option><option>Completed</option><option>Cancelled</option>
          </select>
          <div style={{ background: "#f3f4f6", border: "1px solid #e5e7eb", borderRadius: 3, padding: "3px 12px", fontSize: 11, color: "#374151", fontWeight: 500 }}>
            TOTAL: ${totalRate.toLocaleString("en-US", { minimumFractionDigits: 2 })}
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 6, border: "1px solid #d1d5db", borderRadius: 4, padding: "4px 8px", background: "#fff" }}>
            <svg width={13} height={13} viewBox="0 0 16 16" fill="none">
              <circle cx="6.5" cy="6.5" r="5" stroke="#9ca3af" strokeWidth="1.5"/>
              <path d="M11 11l3.5 3.5" stroke="#9ca3af" strokeWidth="1.5" strokeLinecap="round"/>
            </svg>
            <input type="text" placeholder="Search..." value={search} onChange={e => setSearch(e.target.value)}
              style={{ border: "none", outline: "none", fontSize: 12, width: 150, color: "#374151", background: "transparent" }} />
          </div>
          <button onClick={() => setShowForm(p => !p)} style={{
            background: "#3a8c5c", color: "#fff", border: "none", borderRadius: 4,
            padding: "5px 14px", fontSize: 12, fontWeight: 500, cursor: "pointer",
            display: "flex", alignItems: "center", gap: 5,
          }}
            onMouseEnter={e => e.currentTarget.style.background = "#2d7049"}
            onMouseLeave={e => e.currentTarget.style.background = "#3a8c5c"}>
            + New Load <span style={{ fontSize: 10, opacity: 0.8 }}>▾</span>
          </button>
        </div>
      </div>

      {/* New Load Form */}
      {showForm && (
        <div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 4, padding: "16px", marginBottom: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr 1fr 1fr 200px", gap: 12 }}>

            {/* New Load */}
            <div>
              <SectionTitle icon="📋" text="New Load" />
              <FL label="Status">
                <select style={sStyle} value={form.status} onChange={e => set("status", e.target.value)}>
                  {STATUSES.map(s => <option key={s}>{s}</option>)}
                </select>
              </FL>
              <FL label="Billing Status">
                <select style={sStyle} value={form.billingStatus} onChange={e => set("billingStatus", e.target.value)}>
                  {BILLING_STATUSES.map(s => <option key={s}>{s}</option>)}
                </select>
              </FL>
              <FL label="Dispatcher">
                <select style={sStyle} value={form.dispatcher} onChange={e => set("dispatcher", e.target.value)}>
                  {DISPATCHERS.map(s => <option key={s}>{s}</option>)}
                </select>
              </FL>
            </div>

            {/* Pickup */}
            <div>
              <SectionTitle icon="↑" text="Pickup" />
              <FL label="Date">
                <input type="date" style={iStyle} value={form.pickupDate} onChange={e => set("pickupDate", e.target.value)} />
              </FL>
              <FL label="City">
                <input style={iStyle} value={form.pickupCity} onChange={e => set("pickupCity", e.target.value)} placeholder="City" />
              </FL>
              <FL label="State">
                <select style={sStyle} value={form.pickupState} onChange={e => set("pickupState", e.target.value)}>
                  <option value="">— State —</option>
                  {US_STATES.map(s => <option key={s}>{s}</option>)}
                </select>
              </FL>
              <FL label="Zip">
                <input style={iStyle} value={form.pickupZip} onChange={e => set("pickupZip", e.target.value)} placeholder="Zip" />
              </FL>
            </div>

            {/* Delivery */}
            <div>
              <SectionTitle icon="↓" text="Delivery" />
              <FL label="Date">
                <input type="date" style={iStyle} value={form.deliveryDate} onChange={e => set("deliveryDate", e.target.value)} />
              </FL>
              <FL label="City">
                <input style={iStyle} value={form.deliveryCity} onChange={e => set("deliveryCity", e.target.value)} placeholder="City" />
              </FL>
              <FL label="State">
                <select style={sStyle} value={form.deliveryState} onChange={e => set("deliveryState", e.target.value)}>
                  <option value="">— State —</option>
                  {US_STATES.map(s => <option key={s}>{s}</option>)}
                </select>
              </FL>
              <FL label="Zip">
                <input style={iStyle} value={form.deliveryZip} onChange={e => set("deliveryZip", e.target.value)} placeholder="Zip" />
              </FL>
            </div>

            {/* Broker */}
            <div>
              <SectionTitle icon="📦" text="Broker" />
              <FL label="Broker">
                <select style={sStyle} value={form.broker} onChange={e => set("broker", e.target.value)}>
                  <option value="">— Select —</option>
                  {BROKERS.map(b => <option key={b}>{b}</option>)}
                </select>
              </FL>
              <FL label="PO #">
                <input style={iStyle} value={form.po} onChange={e => set("po", e.target.value)} placeholder="PO number" />
              </FL>
              <FL label="Rate">
                <div style={{ display: "flex", alignItems: "center", border: "1px solid #d1d5db", borderRadius: 3, overflow: "hidden", height: 30 }}>
                  <span style={{ padding: "0 7px", background: "#f9fafb", borderRight: "1px solid #d1d5db", fontSize: 12, color: "#6b7280" }}>$</span>
                  <input style={{ flex: 1, border: "none", outline: "none", padding: "0 8px", fontSize: 12 }}
                    value={form.rate} onChange={e => set("rate", e.target.value)} placeholder="0.00" />
                </div>
              </FL>
            </div>

            {/* Driver */}
            <div>
              <SectionTitle icon="🧑" text="Driver" />
              <FL label="Driver">
                <select style={sStyle} value={form.driver} onChange={e => set("driver", e.target.value)}>
                  <option value="">— Select —</option>
                  {DRIVERS_LIST.map(d => <option key={d}>{d}</option>)}
                </select>
              </FL>
              <FL label="Truck">
                <select style={sStyle} value={form.truck} onChange={e => set("truck", e.target.value)}>
                  <option value="">— Select —</option>
                  {TRUCKS.map(t => <option key={t}>{t}</option>)}
                </select>
              </FL>
              <FL label="Trailer">
                <select style={sStyle} value={form.trailer} onChange={e => set("trailer", e.target.value)}>
                  <option value="">— Select —</option>
                  {TRAILERS.map(t => <option key={t}>{t}</option>)}
                </select>
              </FL>
            </div>

            {/* Notes */}
            <div>
              <SectionTitle icon="📝" text="Notes" />
              <FL label="Notes">
                <textarea value={form.notes} onChange={e => set("notes", e.target.value)}
                  placeholder="Enter notes..."
                  style={{ width: "100%", border: "1px solid #d1d5db", borderRadius: 3, padding: "5px 8px", fontSize: 12, resize: "vertical", minHeight: 80, outline: "none", color: "#374151" }} />
              </FL>
            </div>

            {/* Attachments */}
            <div>
              <SectionTitle icon="📎" text="Attachments" />
              <div
                onClick={() => setAttachModal(true)}
                style={{
                  border: "2px dashed #d1d5db", borderRadius: 4, padding: "14px 10px",
                  textAlign: "center", cursor: "pointer", background: "#fafafa",
                  transition: "all 0.1s",
                }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = "#3a8c5c"; e.currentTarget.style.background = "#f0fdf4"; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = "#d1d5db"; e.currentTarget.style.background = "#fafafa"; }}
              >
                <div style={{ fontSize: 20, color: "#9ca3af", marginBottom: 4 }}>📎</div>
                <div style={{ fontSize: 11, color: "#6b7280" }}>
                  Drag and drop or{" "}
                  <span style={{ color: "#3b82f6", textDecoration: "underline" }}>upload</span>
                </div>
                {form.attachments.length > 0 && (
                  <div style={{ marginTop: 6, fontSize: 10, color: "#3a8c5c", fontWeight: 500 }}>
                    {form.attachments.length} file{form.attachments.length > 1 ? "s" : ""} attached
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Form footer */}
          <div style={{ display: "flex", justifyContent: "flex-end", gap: 8, marginTop: 14, paddingTop: 12, borderTop: "1px solid #e5e7eb" }}>
            <button onClick={() => { setShowForm(false); setForm(emptyForm()); }}
              style={{ padding: "6px 14px", background: "none", border: "1px solid #d1d5db", borderRadius: 4, cursor: "pointer", fontSize: 12, color: "#374151" }}>
              Close
            </button>
            <button onClick={handleCreate} style={{
              display: "flex", alignItems: "center", gap: 5,
              padding: "6px 14px", background: "#3a8c5c", color: "#fff",
              border: "none", borderRadius: 4, cursor: "pointer", fontSize: 12, fontWeight: 500,
            }}>✓ Create Load</button>
          </div>
        </div>
      )}

      {/* Loads Table */}
      <div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 4, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 1100 }}>
            <thead>
              <tr>
                {["Load", "Date", "Driver", "Broker", "PO #", "Pickup", "Delivery", "Rate", "Completed", "Status", "Billing", "Notes", "Attach.", "Actions"].map(h => (
                  <th key={h} style={{ background: "#f9fafb", color: "#6b7280", fontSize: 11, fontWeight: 500, padding: "7px 10px", textAlign: "left", borderBottom: "1px solid #e5e7eb", whiteSpace: "nowrap" }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 ? (
                <tr><td colSpan={14} style={{ padding: "40px", textAlign: "center", color: "#9ca3af", fontSize: 12 }}>No loads found.</td></tr>
              ) : filtered.map(load => (
                <tr key={load.id} style={{ borderBottom: "1px solid #f3f4f6" }}
                  onMouseEnter={e => e.currentTarget.style.background = "#fafafa"}
                  onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                  <td style={{ padding: "7px 10px", fontSize: 12 }}>
                    <a href="#" style={{ color: "#3b82f6", textDecoration: "none", fontWeight: 500 }}>{load.id}</a>
                  </td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#374151" }}>{load.date}</td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#374151" }}>{load.driver}</td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#374151" }}>{load.broker}</td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#6b7280" }}>{load.po}</td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#374151", maxWidth: 140, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{load.pickup}</td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#374151", maxWidth: 140, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{load.delivery}</td>
                  <td style={{ padding: "7px 10px", fontSize: 12, fontWeight: 500, color: "#111827" }}>{load.rate}</td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#6b7280" }}>{load.completed}</td>
                  <td style={{ padding: "7px 10px" }}><StatusBadge status={load.status} /></td>
                  <td style={{ padding: "7px 10px" }}><StatusBadge status={load.billing} /></td>
                  <td style={{ padding: "7px 10px", fontSize: 12, color: "#6b7280", maxWidth: 100, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{load.notes || "—"}</td>
                  <td style={{ padding: "7px 10px", textAlign: "center" }}>
                    {load.attachments > 0 ? (
                      <span style={{ background: "#dbeafe", color: "#1d4ed8", padding: "1px 6px", borderRadius: 3, fontSize: 10, fontWeight: 500 }}>📎 {load.attachments}</span>
                    ) : <span style={{ color: "#d1d5db", fontSize: 12 }}>—</span>}
                  </td>
                  <td style={{ padding: "7px 10px" }}>
                    <div style={{ display: "flex", gap: 4 }}>
                      {["✎", "👁", "✕"].map((ic, i) => (
                        <button key={i} style={{ background: "none", border: "1px solid #d1d5db", borderRadius: 3, padding: "2px 6px", cursor: "pointer", color: i === 2 ? "#dc2626" : "#374151", fontSize: 10 }}
                          onMouseEnter={e => e.currentTarget.style.background = "#f3f4f6"}
                          onMouseLeave={e => e.currentTarget.style.background = "none"}>{ic}</button>
                      ))}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{ minHeight: 60, borderTop: "1px solid #f3f4f6" }} />
        <div style={{ padding: "8px 12px", borderTop: "1px solid #e5e7eb", background: "#f9fafb", fontSize: 11, color: "#6b7280" }}>
          Showing {filtered.length} of {loads.length} entries
        </div>
      </div>
    </div>
  );
}
